class Point:
    def __new__(cls, x, y):
        print(f'__new__: creating {cls.__name__}')
        return super().__new__(cls)  # allocates memory

    def __init__(self, x, y):
        print(f'__init__: setting ({x}, {y})')
        self.x = x
        self.y = y

    # Instance method
    def magnitude(self):
        return (self.x**2 + self.y**2)**0.5

    # Class method — factory
    @classmethod
    def origin(cls):
        return cls(0, 0)

    # Static method — utility
    @staticmethod
    def distance(a, b):
        return ((a.x - b.x)**2 + (a.y - b.y)**2)**0.5

p = Point(3, 4)
print(p.magnitude())         # 5.0
print(Point.origin())        # Point(0, 0)
print(Point.distance(p, Point(0, 0)))  # 5.0

# === MRO demonstration ===
class A:
    def who(self): return 'A'
class B(A):
    def who(self): return 'B'
class C(A):
    def who(self): return 'C'
class D(B, C):
    pass

print(D.__mro__)  # D -> B -> C -> A -> object
print(D().who())  # 'B'

