class LogMixin:
    def save(self):
        print('log')
        super().save()  # continues MRO chain

class Model:
    def save(self):
        print('db')

class LoggedModel(LogMixin, Model):
    pass

LoggedModel().save()  # log, db

# === @property with name mangling ===
class Temperature:
    def __init__(self, celsius):
        self.__celsius = celsius  # name-mangled to _Temperature__celsius

    @property
    def celsius(self):
        return self.__celsius

    @celsius.setter
    def celsius(self, val):
        if val < -273.15:
            raise ValueError('Below absolute zero')
        self.__celsius = val

    @property
    def fahrenheit(self):
        return self.celsius * 9/5 + 32

t = Temperature(25)
print(t.fahrenheit)  # 77.0
t.celsius = 30
print(t.fahrenheit)  # 86.0

from functools import total_ordering

@total_ordering  # generates __ge__, __gt__, __le__ from __eq__ + __lt__
class Money:
    def __init__(self, amount, currency='USD'):
        self.amount = amount
        self.currency = currency

    def __repr__(self):
        return f'Money({self.amount}, {self.currency!r})'

    def __str__(self):
        return f'{self.currency} {self.amount:.2f}'

    def __eq__(self, other):
        if not isinstance(other, Money): return NotImplemented
        return (self.amount, self.currency) == (other.amount, other.currency)

    def __hash__(self):
        return hash((self.amount, self.currency))

    def __lt__(self, other):
        if not isinstance(other, Money): return NotImplemented
        return self.amount < other.amount

    def __add__(self, other):
        if isinstance(other, (int, float)):
            return Money(self.amount + other, self.currency)
        if isinstance(other, Money) and other.currency == self.currency:
            return Money(self.amount + other.amount, self.currency)
        return NotImplemented

    def __call__(self, factor):
        '''Apply a scaling factor — e.g., tax or discount'''
        return Money(self.amount * factor, self.currency)

m1 = Money(100, 'USD')
m2 = Money(50, 'USD')
print(m1 == m2)       # False (via __eq__)
print(m1 > m2)        # True (via @total_ordering)
print(m1 + 20)        # Money(120, 'USD')
print(m1(1.08))       # Money(108.0, 'USD') — 8% tax via __call__
print({m1, m2})       # set works (via __hash__)

