import functools, time, random

# === Parameterized decorator: retry with backoff ===
def retry(max_attempts=3, base_delay=0.1):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            last_exc = None
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    last_exc = e
                    if attempt < max_attempts - 1:
                        time.sleep(base_delay * (2 ** attempt))
            raise last_exc
        return wrapper
    return decorator

@retry(max_attempts=3, base_delay=0.05)
def flaky_call():
    if random.random() < 0.6:
        raise ConnectionError('timeout')
    return 'ok'

# === Context manager via __enter__/__exit__ ===
class Timer:
    def __enter__(self):
        self.start = time.perf_counter()
        return self
    def __exit__(self, exc_type, exc_val, exc_tb):
        self.elapsed = time.perf_counter() - self.start
        return False  # don't suppress

with Timer() as t:
    sum(range(1_000_000))
print(f'{t.elapsed:.4f}s')

# === contextlib one-liner ===
from contextlib import contextmanager
@contextmanager
def db_transaction(conn):
    cursor = conn.cursor()
    try:
        yield cursor
        conn.commit()
    except:
        conn.rollback()
        raise

# === Singleton via __new__ (thread-safe) ===
import threading
class Config:
    _instance = None
    _lock = threading.Lock()

    def __new__(cls):
        if cls._instance is None:
            with cls._lock:
                if cls._instance is None:
                    cls._instance = super().__new__(cls)
                    cls._instance._data = {}
        return cls._instance

# === Factory ===
class Model(ABC):
    @abstractmethod
    def predict(self, x): ...

class LinearModel(Model):
    def predict(self, x): return sum(x)

class TreeModel(Model):
    def predict(self, x): return max(x)

_MODEL_REGISTRY = {'linear': LinearModel, 'tree': TreeModel}

def model_factory(kind: str) -> Model:
    cls = _MODEL_REGISTRY.get(kind)
    if not cls:
        raise ValueError(f'Unknown model: {kind}')
    return cls()

# === Observer (event bus) ===
from collections import defaultdict
class EventBus:
    def __init__(self):
        self._listeners = defaultdict(list)

    def on(self, event, callback):
        self._listeners[event].append(callback)

    def emit(self, event, **data):
        for cb in self._listeners[event]:
            cb(**data)

bus = EventBus()
bus.on('user_signup', lambda email, **_: print(f'Welcome {email}'))
bus.on('user_signup', lambda **_: print('Audit log'))
bus.emit('user_signup', email='alice@example.com')

# === Strategy ===
class PricingStrategy(ABC):
    @abstractmethod
    def calculate(self, base_price): ...

class StandardPricing(PricingStrategy):
    def calculate(self, p): return p

class HolidayPricing(PricingStrategy):
    def calculate(self, p): return p * 1.2

class Order:
    def __init__(self, strategy: PricingStrategy):
        self._strategy = strategy
    def total(self, base):
        return self._strategy.calculate(base)

# === Descriptor for lazy evaluation ===
class LazyProperty:
    def __init__(self, func):
        self.func = func
        self.name = func.__name__

    def __get__(self, obj, cls):
        if obj is None:
            return self
        value = self.func(obj)
        obj.__dict__[self.name] = value  # cache in instance dict
        return value

# === Metaclass for auto-registration ===
class ModelMeta(type):
    def __new__(mcs, name, bases, namespace):
        cls = super().__new__(mcs, name, bases, namespace)
        if not getattr(cls, '_abstract', False):
            # Auto-register non-abstract models
            cls._registry[name] = cls
        return cls

class BaseModel(metaclass=ModelMeta):
    _abstract = True
    _registry = {}

class User(BaseModel):
    pass

print(BaseModel._registry)  # {'User': <class 'User'>}

# === Weakref for cache ===
import weakref
class ImageCache:
    def __init__(self):
        self._cache = weakref.WeakValueDictionary()

    def get(self, key):
        return self._cache.get(key)

    def set(self, key, value):
        self._cache[key] = value

# === Serialization ===
class Model:
    def __init__(self):
        self.loaded = True

    def __getstate__(self):
        # Exclude expensive resources from pickle
        state = self.__dict__.copy()
        state.pop('_connection', None)
        return state

    def __setstate__(self, state):
        self.__dict__.update(state)
        self._connection = None  # reconnect on access
